let files = [];
try { files = fs.readdirSync(pendingDir); } catch(e) { return []; }
const result = [];
for (var i = 0; i < files.length; i++) {
  var f = files[i];
  if (!f.endsWith('.md')) continue;
  var filePath = path.join(pendingDir, f);
  var content = '';
  try { content = fs.readFileSync(filePath, 'utf-8'); } catch(e) { continue; }
  var fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
  var frontmatter = fmMatch ? fmMatch[1] : '';
  var isDone = /status:\s*done/i.test(frontmatter) || /status:\s*\n\s*-\s*done/i.test(frontmatter);
  if (!isDone) continue;
  var origMatch = frontmatter.match(/original_file:\s*"?([^"\n]+)"?/);
  var originalFile = origMatch ? origMatch[1].trim() : '';
  result.push({ json: { name: f, path: path.join('\u5f85\u786e\u8ba4', f).replace(/\\/g, '/'), type: 'file', originalFile: originalFile } });
}
return result;

